var COURSE_PL_NL = [{day: 1, title: `Pierwsze powitania`, title_native: `Eerste begroetingen`, focus: `Dziś uczysz się najprostszych powitań i pożegnań, które przydadzą się od razu po przyjeździe do Amsterdamu, Rotterdamu lub Utrechtu. Celem jest brzmieć uprzejmie i naturalnie w pierwszym kontakcie.`, vocab: [{nl: `hallo`, pl: `cześć`, ipa: `/ha-lo/`},{nl: `goedemorgen`, pl: `dzień dobry rano`, ipa: `/chu-de-mor-chen/`},{nl: `goedemiddag`, pl: `dzień dobry po południu`, ipa: `/chu-de-mi-dach/`},{nl: `goedenavond`, pl: `dobry wieczór`, ipa: `/chu-de-na-font/`},{nl: `dag`, pl: `cześć, do widzenia`, ipa: `/dach/`},{nl: `tot ziens`, pl: `do widzenia`, ipa: `/tot zins/`},{nl: `doei`, pl: `pa`, ipa: `/duj/`},{nl: `alsjeblieft`, pl: `proszę, nieformalnie`, ipa: `/als-je-blift/`},{nl: `dank je`, pl: `dziękuję`, ipa: `/dank je/`},{nl: `ja`, pl: `tak`, ipa: `/ja/`}], phrases: [{nl: `Hallo, hoe gaat het?`, pl: `Cześć, jak się masz?`, ipa: `/ha-lo hu chat het/`},{nl: `Goedemorgen.`, pl: `Dzień dobry rano.`, ipa: `/chu-de-mor-chen/`},{nl: `Dank je.`, pl: `Dziękuję.`, ipa: `/dank je/`},{nl: `Tot ziens.`, pl: `Do widzenia.`, ipa: `/tot zins/`},{nl: `Ja, graag.`, pl: `Tak, chętnie.`, ipa: `/ja chrach/`},{nl: `Nee, dank je.`, pl: `Nie, dziękuję.`, ipa: `/nej dank je/`}], grammar: `W niderlandzkim często używa się krótkich, prostych zwrotów grzecznościowych. „Hallo” jest neutralne i bezpieczne w większości sytuacji, a „goedemorgen”, „goedemiddag” i „goedenavond” brzmią bardziej uprzejmie. „Dag” może znaczyć zarówno „cześć”, jak i „do widzenia”, zależnie od sytuacji.`, practice: [`Powiedz po niderlandzku „Dzień dobry rano”.`,`Odpowiedz krótko „Tak, chętnie”.`,`Przećwicz pożegnanie w sklepie: „Tot ziens”.`,`Wybierz właściwe powitanie wieczorem.`,`Ułóż mini-dialog z „Hallo” i „Dank je”.`]},{day: 2, title: `Przedstawianie się`, title_native: `Jezelf voorstellen`, focus: `Dziś uczysz się mówić, jak masz na imię i skąd jesteś. Przyda się to w hostelu w Amsterdamie, podczas wycieczki kanałami lub przy poznawaniu lokalnych osób.`, vocab: [{nl: `ik`, pl: `ja`, ipa: `/ik/`},{nl: `jij`, pl: `ty`, ipa: `/jej/`},{nl: `u`, pl: `pan, pani`, ipa: `/ü/`},{nl: `naam`, pl: `imię, nazwa`, ipa: `/nam/`},{nl: `mijn`, pl: `mój, moja`, ipa: `/mejn/`},{nl: `Polen`, pl: `Polska`, ipa: `/po-len/`},{nl: `Nederland`, pl: `Holandia, Niderlandy`, ipa: `/ne-der-lant/`},{nl: `waar`, pl: `gdzie`, ipa: `/war/`},{nl: `vandaan`, pl: `skąd`, ipa: `/fan-dan/`},{nl: `aangenaam`, pl: `miło mi`, ipa: `/an-che-nam/`}], phrases: [{nl: `Ik ben Anna.`, pl: `Jestem Anna.`, ipa: `/ik ben an-na/`},{nl: `Mijn naam is Piotr.`, pl: `Mam na imię Piotr.`, ipa: `/mejn nam is pjo-tr/`},{nl: `Ik kom uit Polen.`, pl: `Pochodzę z Polski.`, ipa: `/ik kom aut po-len/`},{nl: `Waar kom je vandaan?`, pl: `Skąd pochodzisz?`, ipa: `/war kom je fan-dan/`},{nl: `Aangenaam.`, pl: `Miło mi.`, ipa: `/an-che-nam/`},{nl: `En jij?`, pl: `A ty?`, ipa: `/en jej/`}], grammar: `Czasownik „zijn” oznacza „być”, a forma „ik ben” znaczy „ja jestem”. Do mówienia o pochodzeniu używa się konstrukcji „Ik kom uit...”, czyli dosłownie „przychodzę z...”. W rozmowie nieformalnej używaj „jij”, a w bardziej uprzejmej sytuacji „u”.`, practice: [`Przedstaw się zdaniem „Ik ben...”.`,`Powiedz, że pochodzisz z Polski.`,`Zapytaj rozmówcę, skąd pochodzi.`,`Odpowiedz „Miło mi” po niderlandzku.`,`Stwórz krótki dialog poznawczy w hostelu.`]},{day: 3, title: `Podstawowe uprzejmości`, title_native: `Basisbeleefdheid`, focus: `Dziś ćwiczysz zwroty, które pomagają być uprzejmym w kawiarni, hotelu i sklepie. W Niderlandach komunikacja bywa bezpośrednia, ale grzeczne „proszę” i „dziękuję” zawsze się przydają.`, vocab: [{nl: `bedankt`, pl: `dzięki`, ipa: `/be-dankt/`},{nl: `dank u`, pl: `dziękuję, formalnie`, ipa: `/dank ü/`},{nl: `alstublieft`, pl: `proszę, formalnie`, ipa: `/als-tü-blift/`},{nl: `sorry`, pl: `przepraszam`, ipa: `/so-ri/`},{nl: `pardon`, pl: `przepraszam`, ipa: `/par-don/`},{nl: `geen probleem`, pl: `nie ma problemu`, ipa: `/chejn pro-blejm/`},{nl: `goed`, pl: `dobrze`, ipa: `/chut/`},{nl: `slecht`, pl: `źle`, ipa: `/slecht/`},{nl: `prima`, pl: `w porządku`, ipa: `/pri-ma/`},{nl: `oké`, pl: `okej`, ipa: `/o-kej/`}], phrases: [{nl: `Dank u wel.`, pl: `Bardzo dziękuję.`, ipa: `/dank ü wel/`},{nl: `Alsjeblieft.`, pl: `Proszę.`, ipa: `/als-je-blift/`},{nl: `Sorry, ik begrijp het niet.`, pl: `Przepraszam, nie rozumiem.`, ipa: `/so-ri ik be-chrejp het nit/`},{nl: `Geen probleem.`, pl: `Nie ma problemu.`, ipa: `/chejn pro-blejm/`},{nl: `Het gaat goed.`, pl: `Mam się dobrze.`, ipa: `/het chat chut/`},{nl: `Prima, dank je.`, pl: `W porządku, dzięki.`, ipa: `/pri-ma dank je/`}], grammar: `„Dank je” jest nieformalne, a „dank u” formalne. Podobnie „alsjeblieft” jest mniej formalne, a „alstublieft” bardziej uprzejme. W sklepach, hotelach i przy rozmowie z nieznajomymi bezpiecznie jest używać formy formalnej.`, practice: [`Powiedz formalnie „Bardzo dziękuję”.`,`Przećwicz „Przepraszam, nie rozumiem”.`,`Odpowiedz na pytanie „Hoe gaat het?”.`,`Zamień nieformalne „Dank je” na formalne.`,`Ułóż trzy uprzejme zdania przy ladzie w kawiarni.`]},{day: 4, title: `Liczby od 0 do 20`, title_native: `Getallen van 0 tot 20`, focus: `Dziś uczysz się liczb potrzebnych do płacenia, podawania numeru pokoju i kupowania biletów. Ćwiczenia możesz wyobrazić sobie na dworcu Amsterdam Centraal.`, vocab: [{nl: `nul`, pl: `zero`, ipa: `/nül/`},{nl: `één`, pl: `jeden`, ipa: `/ejn/`},{nl: `twee`, pl: `dwa`, ipa: `/twej/`},{nl: `drie`, pl: `trzy`, ipa: `/dri/`},{nl: `vier`, pl: `cztery`, ipa: `/fir/`},{nl: `vijf`, pl: `pięć`, ipa: `/fejf/`},{nl: `zes`, pl: `sześć`, ipa: `/zes/`},{nl: `zeven`, pl: `siedem`, ipa: `/zej-fen/`},{nl: `acht`, pl: `osiem`, ipa: `/acht/`},{nl: `tien`, pl: `dziesięć`, ipa: `/tin/`}], phrases: [{nl: `Ik wil twee kaartjes.`, pl: `Chcę dwa bilety.`, ipa: `/ik wil twej kar-czes/`},{nl: `Kamer drie, alstublieft.`, pl: `Pokój trzeci, proszę.`, ipa: `/ka-mer dri als-tü-blift/`},{nl: `Het kost vijf euro.`, pl: `To kosztuje pięć euro.`, ipa: `/het kost fejf oj-ro/`},{nl: `Nummer acht.`, pl: `Numer osiem.`, ipa: `/nü-mer acht/`},{nl: `Ik heb één tas.`, pl: `Mam jedną torbę.`, ipa: `/ik heb ejn tas/`},{nl: `Twee koffie, graag.`, pl: `Dwie kawy, poproszę.`, ipa: `/twej ko-fi chrach/`}], grammar: `Liczby w niderlandzkim są bardzo praktyczne, bo często pojawiają się przy cenach i numerach. „Één” z akcentami oznacza wyraźnie liczbę „jeden”, a bez akcentów „een” może też znaczyć „jakiś” lub „a/an”. W mowie różnica zależy głównie od kontekstu.`, practice: [`Policz po niderlandzku od 0 do 10.`,`Powiedz „dwa bilety, proszę”.`,`Podaj numer pokoju: „Kamer drie”.`,`Powiedz, że coś kosztuje pięć euro.`,`Zamów dwie kawy.`]},{day: 5, title: `Więcej liczb i ceny`, title_native: `Meer getallen en prijzen`, focus: `Dziś rozszerzasz liczby do 100 i ćwiczysz pytanie o cenę. Przyda się to na targu Albert Cuypmarkt w Amsterdamie lub w sklepie w Hadze.`, vocab: [{nl: `elf`, pl: `jedenaście`, ipa: `/elf/`},{nl: `twaalf`, pl: `dwanaście`, ipa: `/twalf/`},{nl: `dertien`, pl: `trzynaście`, ipa: `/der-tin/`},{nl: `twintig`, pl: `dwadzieścia`, ipa: `/twin-tach/`},{nl: `dertig`, pl: `trzydzieści`, ipa: `/der-tach/`},{nl: `veertig`, pl: `czterdzieści`, ipa: `/fir-tach/`},{nl: `vijftig`, pl: `pięćdziesiąt`, ipa: `/fejf-tach/`},{nl: `honderd`, pl: `sto`, ipa: `/hon-dert/`},{nl: `euro`, pl: `euro`, ipa: `/oj-ro/`},{nl: `cent`, pl: `cent`, ipa: `/sent/`}], phrases: [{nl: `Hoeveel kost het?`, pl: `Ile to kosztuje?`, ipa: `/hu-fejl kost het/`},{nl: `Dat is tien euro.`, pl: `To jest dziesięć euro.`, ipa: `/dat is tin oj-ro/`},{nl: `Is dat alles?`, pl: `Czy to wszystko?`, ipa: `/is dat al-les/`},{nl: `Ik betaal met kaart.`, pl: `Płacę kartą.`, ipa: `/ik be-tal met kart/`},{nl: `Ik betaal contant.`, pl: `Płacę gotówką.`, ipa: `/ik be-tal kon-tant/`},{nl: `Dat is te duur.`, pl: `To jest za drogie.`, ipa: `/dat is te dür/`}], grammar: `Pytanie „Hoeveel kost het?” jest podstawowym sposobem pytania o cenę. „Te” przed przymiotnikiem oznacza „za”, jak w „te duur” — „za drogie”. W Niderlandach płatność kartą jest bardzo powszechna, więc „Ik betaal met kaart” to szczególnie przydatne zdanie.`, practice: [`Zapytaj po niderlandzku „Ile to kosztuje?”.`,`Powiedz, że płacisz kartą.`,`Powiedz „To jest za drogie”.`,`Przećwicz liczby 20, 30, 40 i 50.`,`Odegraj krótką scenę kupowania owoców na targu.`]},{day: 6, title: `Dni tygodnia i czas`, title_native: `Dagen van de week en tijd`, focus: `Dziś uczysz się dni tygodnia i prostych określeń czasu. To pomoże przy rezerwacjach muzeów w Amsterdamie, biletach kolejowych i planowaniu spotkań.`, vocab: [{nl: `maandag`, pl: `poniedziałek`, ipa: `/man-dach/`},{nl: `dinsdag`, pl: `wtorek`, ipa: `/dins-dach/`},{nl: `woensdag`, pl: `środa`, ipa: `/wuns-dach/`},{nl: `donderdag`, pl: `czwartek`, ipa: `/don-der-dach/`},{nl: `vrijdag`, pl: `piątek`, ipa: `/frej-dach/`},{nl: `zaterdag`, pl: `sobota`, ipa: `/za-ter-dach/`},{nl: `zondag`, pl: `niedziela`, ipa: `/zon-dach/`},{nl: `vandaag`, pl: `dzisiaj`, ipa: `/fan-dach/`},{nl: `morgen`, pl: `jutro`, ipa: `/mor-chen/`},{nl: `gisteren`, pl: `wczoraj`, ipa: `/chis-te-ren/`}], phrases: [{nl: `Welke dag is het vandaag?`, pl: `Jaki dziś dzień?`, ipa: `/wel-ke dach is het fan-dach/`},{nl: `Vandaag is maandag.`, pl: `Dzisiaj jest poniedziałek.`, ipa: `/fan-dach is man-dach/`},{nl: `Morgen ga ik naar Utrecht.`, pl: `Jutro jadę do Utrechtu.`, ipa: `/mor-chen cha ik nar ü-trecht/`},{nl: `Ik heb tijd.`, pl: `Mam czas.`, ipa: `/ik heb teit/`},{nl: `Ik heb geen tijd.`, pl: `Nie mam czasu.`, ipa: `/ik heb chejn teit/`},{nl: `Tot morgen.`, pl: `Do jutra.`, ipa: `/tot mor-chen/`}], grammar: `„Vandaag”, „morgen” i „gisteren” zwykle stoją blisko początku lub końca zdania. „Ik heb” oznacza „mam”, a „geen” zaprzecza rzeczownik bez rodzajnika lub z rodzajnikiem nieokreślonym. „Ik heb geen tijd” dosłownie znaczy „mam nie czas”.`, practice: [`Wymień dni tygodnia po niderlandzku.`,`Powiedz „Dzisiaj jest piątek”.`,`Powiedz „Jutro jadę do Utrechtu”.`,`Zaprzecz zdanie „Ik heb tijd”.`,`Zaplanuj wizytę w muzeum na sobotę.`]},{day: 7, title: `Pytania podstawowe`, title_native: `Basisvragen`, focus: `Dziś uczysz się zadawać proste pytania, które pomogą w każdej podróży. Będziesz ich używać w centrum Rotterdamu, na dworcu i w restauracji.`, vocab: [{nl: `wie`, pl: `kto`, ipa: `/wi/`},{nl: `wat`, pl: `co`, ipa: `/wat/`},{nl: `waar`, pl: `gdzie`, ipa: `/war/`},{nl: `wanneer`, pl: `kiedy`, ipa: `/wa-nir/`},{nl: `waarom`, pl: `dlaczego`, ipa: `/wa-rom/`},{nl: `hoe`, pl: `jak`, ipa: `/hu/`},{nl: `welke`, pl: `który, jaka`, ipa: `/wel-ke/`},{nl: `dit`, pl: `to`, ipa: `/dit/`},{nl: `dat`, pl: `tamto`, ipa: `/dat/`},{nl: `hier`, pl: `tutaj`, ipa: `/hir/`}], phrases: [{nl: `Waar is het station?`, pl: `Gdzie jest stacja?`, ipa: `/war is het sta-sjon/`},{nl: `Wat is dit?`, pl: `Co to jest?`, ipa: `/wat is dit/`},{nl: `Hoe heet je?`, pl: `Jak masz na imię?`, ipa: `/hu hejt je/`},{nl: `Wanneer vertrekt de trein?`, pl: `Kiedy odjeżdża pociąg?`, ipa: `/wa-nir fer-trekt de trejn/`},{nl: `Welke tram gaat naar het centrum?`, pl: `Który tramwaj jedzie do centrum?`, ipa: `/wel-ke tram chat nar het sen-trüm/`},{nl: `Is dit vrij?`, pl: `Czy to jest wolne?`, ipa: `/is dit frej/`}], grammar: `Niderlandzkie pytania często zaczynają się od słowa pytającego, a potem pojawia się czasownik. W zdaniu „Waar is het station?” szyk jest podobny do polskiego, ale w wielu pytaniach czasownik szybko przechodzi na drugie miejsce. Zapamiętuj całe pytania jako gotowe narzędzia podróżne.`, practice: [`Zapytaj „Gdzie jest stacja?”.`,`Zapytaj „Co to jest?”.`,`Zapytaj, kiedy odjeżdża pociąg.`,`Wskaż coś i powiedz „dit”.`,`Ułóż trzy pytania zaczynające się od „waar”, „wat” i „hoe”.`]},{day: 8, title: `Na lotnisku`, title_native: `Op de luchthaven`, focus: `Dziś ćwiczysz zwroty przydatne na lotnisku Schiphol pod Amsterdamem. Nauczysz się pytać o bagaż, kontrolę paszportową i wyjście.`, vocab: [{nl: `luchthaven`, pl: `lotnisko`, ipa: `/lücht-ha-fen/`},{nl: `paspoort`, pl: `paszport`, ipa: `/pas-port/`},{nl: `bagage`, pl: `bagaż`, ipa: `/ba-cha-zje/`},{nl: `koffer`, pl: `walizka`, ipa: `/ko-fer/`},{nl: `poort`, pl: `bramka`, ipa: `/port/`},{nl: `vlucht`, pl: `lot`, ipa: `/flücht/`},{nl: `aankomst`, pl: `przylot`, ipa: `/an-komst/`},{nl: `vertrek`, pl: `odlot`, ipa: `/fer-trek/`},{nl: `controle`, pl: `kontrola`, ipa: `/kon-tro-le/`},{nl: `uitgang`, pl: `wyjście`, ipa: `/aut-chang/`}], phrases: [{nl: `Waar is de uitgang?`, pl: `Gdzie jest wyjście?`, ipa: `/war is de aut-chang/`},{nl: `Ik heb één koffer.`, pl: `Mam jedną walizkę.`, ipa: `/ik heb ejn ko-fer/`},{nl: `Dit is mijn paspoort.`, pl: `To jest mój paszport.`, ipa: `/dit is mejn pas-port/`},{nl: `Waar is de bagage?`, pl: `Gdzie jest bagaż?`, ipa: `/war is de ba-cha-zje/`},{nl: `Welke poort is het?`, pl: `Która to bramka?`, ipa: `/wel-ke port is het/`},{nl: `Mijn vlucht is vertraagd.`, pl: `Mój lot jest opóźniony.`, ipa: `/mejn flücht is fer-traacht/`}], grammar: `„Mijn” oznacza „mój” lub „moja” i nie zmienia formy tak jak w polskim. „De” i „het” to dwa rodzajniki określone, oba znaczą mniej więcej „ten/ta/to”. Na początku najlepiej uczyć się rzeczowników razem z rodzajnikiem: „de uitgang”, „het paspoort”.`, practice: [`Powiedz „To jest mój paszport”.`,`Zapytaj o wyjście na lotnisku.`,`Powiedz, że masz jedną walizkę.`,`Zapytaj, która to bramka.`,`Odegraj krótką rozmowę przy kontroli paszportowej.`]},{day: 9, title: `Hotel i zameldowanie`, title_native: `Hotel en inchecken`, focus: `Dziś uczysz się meldować w hotelu w Hadze lub Amsterdamie. Przydadzą się zwroty dotyczące rezerwacji, pokoju, klucza i śniadania.`, vocab: [{nl: `hotel`, pl: `hotel`, ipa: `/ho-tel/`},{nl: `reservering`, pl: `rezerwacja`, ipa: `/re-zer-fe-ring/`},{nl: `kamer`, pl: `pokój`, ipa: `/ka-mer/`},{nl: `sleutel`, pl: `klucz`, ipa: `/slöj-tel/`},{nl: `ontbijt`, pl: `śniadanie`, ipa: `/ont-bejt/`},{nl: `receptie`, pl: `recepcja`, ipa: `/re-sep-si/`},{nl: `nacht`, pl: `noc`, ipa: `/nacht/`},{nl: `bed`, pl: `łóżko`, ipa: `/bet/`},{nl: `badkamer`, pl: `łazienka`, ipa: `/bat-ka-mer/`},{nl: `lift`, pl: `winda`, ipa: `/lift/`}], phrases: [{nl: `Ik heb een reservering.`, pl: `Mam rezerwację.`, ipa: `/ik heb en re-zer-fe-ring/`},{nl: `Op naam van Kowalski.`, pl: `Na nazwisko Kowalski.`, ipa: `/op nam fan ko-wal-ski/`},{nl: `Waar is mijn kamer?`, pl: `Gdzie jest mój pokój?`, ipa: `/war is mejn ka-mer/`},{nl: `Is ontbijt inbegrepen?`, pl: `Czy śniadanie jest wliczone?`, ipa: `/is ont-bejt in-be-chre-pen/`},{nl: `Mag ik de sleutel?`, pl: `Czy mogę dostać klucz?`, ipa: `/mach ik de slöj-tel/`},{nl: `Waar is de lift?`, pl: `Gdzie jest winda?`, ipa: `/war is de lift/`}], grammar: `„Ik heb een reservering” to bardzo przydatne zdanie w hotelu. „Een” oznacza „jakiś/jeden” i jest rodzajnikiem nieokreślonym. Pytanie z „mag ik...?” oznacza „czy mogę...?” i brzmi uprzejmie w praktycznych sytuacjach.`, practice: [`Powiedz, że masz rezerwację.`,`Podaj nazwisko przy recepcji.`,`Zapytaj, czy śniadanie jest wliczone.`,`Zapytaj, gdzie jest winda.`,`Ułóż dialog zameldowania w hotelu.`]},{day: 10, title: `Kierunki i orientacja`, title_native: `Richtingen en oriëntatie`, focus: `Dziś uczysz się pytać o drogę i rozumieć proste wskazówki. Przyda się to podczas spaceru po kanałach Amsterdamu lub w centrum Utrechtu.`, vocab: [{nl: `links`, pl: `lewo`, ipa: `/links/`},{nl: `rechts`, pl: `prawo`, ipa: `/rechts/`},{nl: `rechtdoor`, pl: `prosto`, ipa: `/recht-dor/`},{nl: `straat`, pl: `ulica`, ipa: `/strat/`},{nl: `plein`, pl: `plac`, ipa: `/plejn/`},{nl: `brug`, pl: `most`, ipa: `/brüch/`},{nl: `hoek`, pl: `róg`, ipa: `/huk/`},{nl: `centrum`, pl: `centrum`, ipa: `/sen-trüm/`},{nl: `dichtbij`, pl: `blisko`, ipa: `/dicht-bej/`},{nl: `ver`, pl: `daleko`, ipa: `/fer/`}], phrases: [{nl: `Ga rechtdoor.`, pl: `Idź prosto.`, ipa: `/cha recht-dor/`},{nl: `Sla linksaf.`, pl: `Skręć w lewo.`, ipa: `/sla links-af/`},{nl: `Sla rechtsaf.`, pl: `Skręć w prawo.`, ipa: `/sla rechts-af/`},{nl: `Het is dichtbij.`, pl: `To jest blisko.`, ipa: `/het is dicht-bej/`},{nl: `Is het ver?`, pl: `Czy to daleko?`, ipa: `/is het fer/`},{nl: `Bij de brug.`, pl: `Przy moście.`, ipa: `/bej de brüch/`}], grammar: `W poleceniach kierunkowych często używa się krótkiej formy czasownika, np. „Ga” — „idź”. „Linksaf” i „rechtsaf” znaczą „w lewo” i „w prawo” przy skręcaniu. W miastach z kanałami słowo „brug” jest bardzo praktyczne, bo mosty są częstymi punktami orientacyjnymi.`, practice: [`Powiedz „Idź prosto”.`,`Powiedz „Skręć w prawo”.`,`Zapytaj, czy coś jest daleko.`,`Opisz trasę: prosto, potem w lewo.`,`Zapytaj o drogę do centrum.`]},{day: 11, title: `Transport publiczny`, title_native: `Openbaar vervoer`, focus: `Dziś ćwiczysz słownictwo związane z tramwajem, metrem, autobusem i pociągiem. To kluczowe w Amsterdamie, Rotterdamie i podczas podróży między miastami.`, vocab: [{nl: `trein`, pl: `pociąg`, ipa: `/trejn/`},{nl: `tram`, pl: `tramwaj`, ipa: `/tram/`},{nl: `bus`, pl: `autobus`, ipa: `/büs/`},{nl: `metro`, pl: `metro`, ipa: `/me-tro/`},{nl: `kaartje`, pl: `bilet`, ipa: `/kar-cze/`},{nl: `station`, pl: `stacja, dworzec`, ipa: `/sta-sjon/`},{nl: `halte`, pl: `przystanek`, ipa: `/hal-te/`},{nl: `spoor`, pl: `peron, tor`, ipa: `/spor/`},{nl: `vertraging`, pl: `opóźnienie`, ipa: `/fer-tra-ching/`},{nl: `overstappen`, pl: `przesiadać się`, ipa: `/o-fer-sta-pen/`}], phrases: [{nl: `Ik wil een kaartje naar Rotterdam.`, pl: `Chcę bilet do Rotterdamu.`, ipa: `/ik wil en kar-cze nar ro-ter-dam/`},{nl: `Welk spoor?`, pl: `Który peron?`, ipa: `/welk spor/`},{nl: `Waar is de tramhalte?`, pl: `Gdzie jest przystanek tramwajowy?`, ipa: `/war is de tram-hal-te/`},{nl: `Moet ik overstappen?`, pl: `Czy muszę się przesiąść?`, ipa: `/mut ik o-fer-sta-pen/`},{nl: `De trein heeft vertraging.`, pl: `Pociąg ma opóźnienie.`, ipa: `/de trejn heft fer-tra-ching/`},{nl: `Ik ga met de metro.`, pl: `Jadę metrem.`, ipa: `/ik cha met de me-tro/`}], grammar: `„Naar” oznacza „do” w kierunku miejsca, np. „naar Rotterdam”. „Met” oznacza „z” lub „za pomocą”, dlatego „met de metro” znaczy „metrem”. W podróży warto zapamiętać całe pytanie „Moet ik overstappen?”, bo przesiadki są częste.`, practice: [`Kup bilet do Rotterdamu.`,`Zapytaj, z którego peronu odjeżdża pociąg.`,`Powiedz, że jedziesz metrem.`,`Zapytaj o przystanek tramwajowy.`,`Powiedz, że pociąg ma opóźnienie.`]},{day: 12, title: `Zamawianie kawy`, title_native: `Koffie bestellen`, focus: `Dziś uczysz się zamawiać kawę i małe przekąski w kawiarni. Scena pasuje do lokalnej kawiarni w Amsterdamie, Delft lub Groningen.`, vocab: [{nl: `koffie`, pl: `kawa`, ipa: `/ko-fi/`},{nl: `thee`, pl: `herbata`, ipa: `/tej/`},{nl: `water`, pl: `woda`, ipa: `/wa-ter/`},{nl: `melk`, pl: `mleko`, ipa: `/melk/`},{nl: `suiker`, pl: `cukier`, ipa: `/söj-ker/`},{nl: `broodje`, pl: `kanapka, bułka`, ipa: `/bro-cze/`},{nl: `taart`, pl: `ciasto`, ipa: `/tart/`},{nl: `kopje`, pl: `filiżanka`, ipa: `/kop-je/`},{nl: `glas`, pl: `szklanka`, ipa: `/chlas/`},{nl: `rekening`, pl: `rachunek`, ipa: `/rej-ke-ning/`}], phrases: [{nl: `Een koffie, graag.`, pl: `Kawę, poproszę.`, ipa: `/en ko-fi chrach/`},{nl: `Met melk, alstublieft.`, pl: `Z mlekiem, proszę.`, ipa: `/met melk als-tü-blift/`},{nl: `Zonder suiker.`, pl: `Bez cukru.`, ipa: `/zon-der söj-ker/`},{nl: `Mag ik een glas water?`, pl: `Czy mogę dostać szklankę wody?`, ipa: `/mach ik en chlas wa-ter/`},{nl: `Voor hier of om mee te nemen?`, pl: `Na miejscu czy na wynos?`, ipa: `/for hir of om mej te nej-men/`},{nl: `Voor hier, graag.`, pl: `Na miejscu, poproszę.`, ipa: `/for hir chrach/`}], grammar: `„Met” oznacza „z”, a „zonder” oznacza „bez”. W kawiarni często usłyszysz pytanie „Voor hier of om mee te nemen?” — dosłownie „tutaj czy do zabrania”. Odpowiedzi „Voor hier” i „Om mee te nemen” są bardzo praktyczne.`, practice: [`Zamów kawę z mlekiem.`,`Poproś o herbatę bez cukru.`,`Odpowiedz, że chcesz na miejscu.`,`Poproś o szklankę wody.`,`Ułóż dialog w kawiarni na 4 linie.`]},{day: 13, title: `W restauracji`, title_native: `In het restaurant`, focus: `Dziś ćwiczysz jedzenie w restauracji, pytanie o stolik i zamawianie posiłku. Przyda się to w Rotterdamie, Hadze lub podczas kolacji przy kanale w Amsterdamie.`, vocab: [{nl: `restaurant`, pl: `restauracja`, ipa: `/res-to-rant/`},{nl: `tafel`, pl: `stolik`, ipa: `/ta-fel/`},{nl: `menu`, pl: `menu`, ipa: `/me-nü/`},{nl: `eten`, pl: `jedzenie, jeść`, ipa: `/e-ten/`},{nl: `drinken`, pl: `picie, pić`, ipa: `/drin-ken/`},{nl: `soep`, pl: `zupa`, ipa: `/sup/`},{nl: `vis`, pl: `ryba`, ipa: `/fis/`},{nl: `vlees`, pl: `mięso`, ipa: `/flejs/`},{nl: `groente`, pl: `warzywa`, ipa: `/chrun-te/`},{nl: `lekker`, pl: `smaczny`, ipa: `/le-ker/`}], phrases: [{nl: `Heeft u een tafel voor twee?`, pl: `Czy mają państwo stolik dla dwóch osób?`, ipa: `/heft ü en ta-fel for twej/`},{nl: `Mag ik het menu?`, pl: `Czy mogę dostać menu?`, ipa: `/mach ik het me-nü/`},{nl: `Ik wil de soep.`, pl: `Chcę zupę.`, ipa: `/ik wil de sup/`},{nl: `Wat raadt u aan?`, pl: `Co pan/pani poleca?`, ipa: `/wat rat ü an/`},{nl: `Het is lekker.`, pl: `To jest smaczne.`, ipa: `/het is le-ker/`},{nl: `Mag ik de rekening?`, pl: `Czy mogę dostać rachunek?`, ipa: `/mach ik de rej-ke-ning/`}], grammar: `„Heeft u...?” to formalne pytanie „Czy ma pan/pani...?”. W restauracji brzmi naturalnie i grzecznie. „Voor twee” oznacza „dla dwóch osób”, a liczbę możesz zmienić zależnie od sytuacji.`, practice: [`Poproś o stolik dla dwóch osób.`,`Poproś o menu.`,`Zapytaj, co kelner poleca.`,`Powiedz, że jedzenie jest smaczne.`,`Poproś o rachunek.`]},{day: 14, title: `Preferencje i alergie`, title_native: `Voorkeuren en allergieën`, focus: `Dziś uczysz się mówić o preferencjach jedzeniowych i alergiach. To ważne, gdy zamawiasz jedzenie w restauracji lub kupujesz przekąski w supermarkecie.`, vocab: [{nl: `vegetarisch`, pl: `wegetariański`, ipa: `/we-che-ta-ris/`},{nl: `veganistisch`, pl: `wegański`, ipa: `/we-cha-nis-tis/`},{nl: `allergie`, pl: `alergia`, ipa: `/a-ler-chi/`},{nl: `noten`, pl: `orzechy`, ipa: `/no-ten/`},{nl: `melk`, pl: `mleko`, ipa: `/melk/`},{nl: `gluten`, pl: `gluten`, ipa: `/chlü-ten/`},{nl: `ei`, pl: `jajko`, ipa: `/ej/`},{nl: `kaas`, pl: `ser`, ipa: `/kas/`},{nl: `kip`, pl: `kurczak`, ipa: `/kip/`},{nl: `zonder`, pl: `bez`, ipa: `/zon-der/`}], phrases: [{nl: `Ik ben vegetarisch.`, pl: `Jestem wegetarianinem/wegetarianką.`, ipa: `/ik ben we-che-ta-ris/`},{nl: `Ik heb een allergie.`, pl: `Mam alergię.`, ipa: `/ik heb en a-ler-chi/`},{nl: `Zonder kaas, alstublieft.`, pl: `Bez sera, proszę.`, ipa: `/zon-der kas als-tü-blift/`},{nl: `Zit er melk in?`, pl: `Czy jest w tym mleko?`, ipa: `/zit er melk in/`},{nl: `Ik eet geen vlees.`, pl: `Nie jem mięsa.`, ipa: `/ik ejt chejn flejs/`},{nl: `Is dit veganistisch?`, pl: `Czy to jest wegańskie?`, ipa: `/is dit we-cha-nis-tis/`}], grammar: `„Geen” służy do zaprzeczania rzeczowników, np. „geen vlees” — „żadnego mięsa”. Pytanie „Zit er ... in?” jest bardzo przydatne przy składnikach i znaczy „Czy jest w tym...?”. W sytuacjach zdrowotnych mów jasno i prosto.`, practice: [`Powiedz, że masz alergię.`,`Zapytaj, czy w daniu jest mleko.`,`Zamów coś bez sera.`,`Powiedz, że nie jesz mięsa.`,`Zapytaj, czy coś jest wegańskie.`]},{day: 15, title: `Zakupy spożywcze`, title_native: `Boodschappen doen`, focus: `Dziś uczysz się kupować podstawowe produkty w supermarkecie lub na targu. Scena pasuje do sklepu Albert Heijn, Jumbo albo lokalnego targu.`, vocab: [{nl: `supermarkt`, pl: `supermarket`, ipa: `/sü-per-markt/`},{nl: `brood`, pl: `chleb`, ipa: `/brot/`},{nl: `kaas`, pl: `ser`, ipa: `/kas/`},{nl: `appel`, pl: `jabłko`, ipa: `/a-pel/`},{nl: `banaan`, pl: `banan`, ipa: `/ba-nan/`},{nl: `fles`, pl: `butelka`, ipa: `/fles/`},{nl: `zak`, pl: `torba`, ipa: `/zak/`},{nl: `mandje`, pl: `koszyk`, ipa: `/man-cze/`},{nl: `kassa`, pl: `kasa`, ipa: `/ka-sa/`},{nl: `bon`, pl: `paragon`, ipa: `/bon/`}], phrases: [{nl: `Waar is het brood?`, pl: `Gdzie jest chleb?`, ipa: `/war is het brot/`},{nl: `Ik zoek kaas.`, pl: `Szukam sera.`, ipa: `/ik zuk kas/`},{nl: `Heeft u een zak?`, pl: `Czy ma pan/pani torbę?`, ipa: `/heft ü en zak/`},{nl: `Wilt u de bon?`, pl: `Czy chce pan/pani paragon?`, ipa: `/wilt ü de bon/`},{nl: `Ja, graag.`, pl: `Tak, poproszę.`, ipa: `/ja chrach/`},{nl: `Nee, bedankt.`, pl: `Nie, dziękuję.`, ipa: `/nej be-dankt/`}], grammar: `„Ik zoek...” oznacza „szukam...” i jest bardzo przydatne w sklepie. W pytaniach obsługa często używa „Wilt u...?”, czyli „Czy chce pan/pani...?”. Odpowiedzi „Ja, graag” i „Nee, bedankt” są krótkie i naturalne.`, practice: [`Powiedz, że szukasz sera.`,`Zapytaj, gdzie jest chleb.`,`Poproś o torbę.`,`Odpowiedz, że nie chcesz paragonu.`,`Odegraj scenę przy kasie.`]},{day: 16, title: `Ubrania i rozmiary`, title_native: `Kleding en maten`, focus: `Dziś uczysz się kupować ubrania i pytać o rozmiar. Przyda się to w centrum handlowym w Rotterdamie lub w butikach w Amsterdamie.`, vocab: [{nl: `kleding`, pl: `ubrania`, ipa: `/klej-ding/`},{nl: `shirt`, pl: `koszulka`, ipa: `/szirt/`},{nl: `broek`, pl: `spodnie`, ipa: `/bruk/`},{nl: `jas`, pl: `kurtka, płaszcz`, ipa: `/jas/`},{nl: `schoenen`, pl: `buty`, ipa: `/schu-nen/`},{nl: `maat`, pl: `rozmiar`, ipa: `/mat/`},{nl: `kleur`, pl: `kolor`, ipa: `/klör/`},{nl: `blauw`, pl: `niebieski`, ipa: `/blau/`},{nl: `zwart`, pl: `czarny`, ipa: `/zwart/`},{nl: `wit`, pl: `biały`, ipa: `/wit/`}], phrases: [{nl: `Heeft u deze in maat M?`, pl: `Czy mają państwo to w rozmiarze M?`, ipa: `/heft ü de-ze in mat em/`},{nl: `Ik zoek schoenen.`, pl: `Szukam butów.`, ipa: `/ik zuk schu-nen/`},{nl: `Kan ik dit passen?`, pl: `Czy mogę to przymierzyć?`, ipa: `/kan ik dit pa-sen/`},{nl: `Waar is de paskamer?`, pl: `Gdzie jest przymierzalnia?`, ipa: `/war is de pas-ka-mer/`},{nl: `Deze kleur is mooi.`, pl: `Ten kolor jest ładny.`, ipa: `/de-ze klör is moj/`},{nl: `Het is te klein.`, pl: `To jest za małe.`, ipa: `/het is te klejn/`}], grammar: `„Deze” oznacza „ten/ta/te” dla rzeczy blisko ciebie, a „dit” znaczy „to”. Przy ubraniach często używa się „passen” — „przymierzać”. Zwrot „te klein” oznacza „za małe”, a „te groot” — „za duże”.`, practice: [`Zapytaj o rozmiar M.`,`Powiedz, że szukasz butów.`,`Zapytaj o przymierzalnię.`,`Powiedz, że coś jest za małe.`,`Opisz kolor ubrania.`]},{day: 17, title: `W mieście i zwiedzanie`, title_native: `In de stad en sightseeing`, focus: `Dziś uczysz się słów związanych ze zwiedzaniem miasta. Będziesz pytać o muzea, kanały, place i ciekawe miejsca w Amsterdamie, Lejdzie lub Gandawie.`, vocab: [{nl: `museum`, pl: `muzeum`, ipa: `/mü-ze-üm/`},{nl: `kanaal`, pl: `kanał`, ipa: `/ka-nal/`},{nl: `kerk`, pl: `kościół`, ipa: `/kerk/`},{nl: `markt`, pl: `targ, rynek`, ipa: `/markt/`},{nl: `park`, pl: `park`, ipa: `/park/`},{nl: `foto`, pl: `zdjęcie`, ipa: `/fo-to/`},{nl: `kaart`, pl: `mapa`, ipa: `/kart/`},{nl: `rondleiding`, pl: `wycieczka z przewodnikiem`, ipa: `/ront-lej-ding/`},{nl: `ingang`, pl: `wejście`, ipa: `/in-chang/`},{nl: `ticket`, pl: `bilet`, ipa: `/ti-ket/`}], phrases: [{nl: `Waar is het museum?`, pl: `Gdzie jest muzeum?`, ipa: `/war is het mü-ze-üm/`},{nl: `Mag ik een foto maken?`, pl: `Czy mogę zrobić zdjęcie?`, ipa: `/mach ik en fo-to ma-ken/`},{nl: `Hoe laat begint de rondleiding?`, pl: `O której zaczyna się wycieczka?`, ipa: `/hu lat be-chint de ront-lej-ding/`},{nl: `Is de ingang hier?`, pl: `Czy wejście jest tutaj?`, ipa: `/is de in-chang hir/`},{nl: `Ik heb een ticket.`, pl: `Mam bilet.`, ipa: `/ik heb en ti-ket/`},{nl: `De stad is mooi.`, pl: `Miasto jest piękne.`, ipa: `/de stat is moj/`}], grammar: `„Hoe laat” oznacza „o której godzinie”. Czasownik „maken” znaczy „robić”, więc „een foto maken” to „zrobić zdjęcie”. W muzeach i kościołach warto pytać o pozwolenie, używając „Mag ik...?”`, practice: [`Zapytaj, gdzie jest muzeum.`,`Zapytaj, czy możesz zrobić zdjęcie.`,`Powiedz, że masz bilet.`,`Zapytaj, gdzie jest wejście.`,`Opisz miasto jednym zdaniem.`]},{day: 18, title: `Godziny otwarcia`, title_native: `Openingstijden`, focus: `Dziś uczysz się pytać, czy miejsce jest otwarte i o której godzinie coś się zaczyna. Przyda się to przy muzeach, sklepach, restauracjach i atrakcjach turystycznych.`, vocab: [{nl: `open`, pl: `otwarte`, ipa: `/o-pen/`},{nl: `gesloten`, pl: `zamknięte`, ipa: `/che-slo-ten/`},{nl: `uur`, pl: `godzina`, ipa: `/ür/`},{nl: `half`, pl: `pół`, ipa: `/half/`},{nl: `kwart`, pl: `kwadrans`, ipa: `/kwart/`},{nl: `vandaag`, pl: `dzisiaj`, ipa: `/fan-dach/`},{nl: `avond`, pl: `wieczór`, ipa: `/a-font/`},{nl: `ochtend`, pl: `poranek`, ipa: `/och-tent/`},{nl: `middag`, pl: `południe, popołudnie`, ipa: `/mi-dach/`},{nl: `laat`, pl: `późno`, ipa: `/lat/`}], phrases: [{nl: `Hoe laat is het open?`, pl: `O której jest otwarte?`, ipa: `/hu lat is het o-pen/`},{nl: `Het is gesloten.`, pl: `Jest zamknięte.`, ipa: `/het is che-slo-ten/`},{nl: `Om negen uur.`, pl: `O dziewiątej.`, ipa: `/om ne-chen ür/`},{nl: `Tot hoe laat bent u open?`, pl: `Do której jest otwarte?`, ipa: `/tot hu lat bent ü o-pen/`},{nl: `De winkel is vandaag open.`, pl: `Sklep jest dziś otwarty.`, ipa: `/de win-kel is fan-dach o-pen/`},{nl: `Het is te laat.`, pl: `Jest za późno.`, ipa: `/het is te lat/`}], grammar: `Godzinę podaje się często z „om”, np. „om negen uur” — „o dziewiątej”. „Open” i „gesloten” są bardzo praktyczne i mogą działać jak przymiotniki. W pytaniu formalnym „bent u open?” zwracasz się do sklepu lub obsługi grzecznie.`, practice: [`Zapytaj, o której miejsce jest otwarte.`,`Powiedz „Jest zamknięte”.`,`Powiedz „o dziewiątej”.`,`Zapytaj, do której sklep jest otwarty.`,`Ułóż scenę przy zamkniętym muzeum.`]},{day: 19, title: `Pogoda`, title_native: `Het weer`, focus: `Dziś uczysz się mówić o pogodzie, co w Niderlandach jest bardzo praktyczne. Deszcz, wiatr i zmienne niebo często pojawiają się w codziennych rozmowach.`, vocab: [{nl: `weer`, pl: `pogoda`, ipa: `/wer/`},{nl: `regen`, pl: `deszcz`, ipa: `/rej-chen/`},{nl: `wind`, pl: `wiatr`, ipa: `/wint/`},{nl: `zon`, pl: `słońce`, ipa: `/zon/`},{nl: `koud`, pl: `zimno`, ipa: `/kaut/`},{nl: `warm`, pl: `ciepło`, ipa: `/warm/`},{nl: `bewolkt`, pl: `pochmurno`, ipa: `/be-wolkt/`},{nl: `paraplu`, pl: `parasol`, ipa: `/pa-ra-plü/`},{nl: `jas`, pl: `kurtka`, ipa: `/jas/`},{nl: `nat`, pl: `mokry`, ipa: `/nat/`}], phrases: [{nl: `Hoe is het weer?`, pl: `Jaka jest pogoda?`, ipa: `/hu is het wer/`},{nl: `Het regent.`, pl: `Pada deszcz.`, ipa: `/het rej-chent/`},{nl: `Het is koud vandaag.`, pl: `Dzisiaj jest zimno.`, ipa: `/het is kaut fan-dach/`},{nl: `Er is veel wind.`, pl: `Jest dużo wiatru.`, ipa: `/er is fejl wint/`},{nl: `Ik heb een paraplu nodig.`, pl: `Potrzebuję parasola.`, ipa: `/ik heb en pa-ra-plü no-dich/`},{nl: `Morgen wordt het warm.`, pl: `Jutro będzie ciepło.`, ipa: `/mor-chen wort het warm/`}], grammar: `W opisach pogody często używa się „het”, np. „Het regent” i „Het is koud”. „Nodig hebben” oznacza „potrzebować”, ale w praktyce zapamiętaj gotową formę „Ik heb ... nodig”. Pogoda to dobry temat do krótkiej rozmowy z lokalnymi osobami.`, practice: [`Powiedz, że pada deszcz.`,`Powiedz, że dziś jest zimno.`,`Poproś o parasol lub powiedz, że go potrzebujesz.`,`Zapytaj o pogodę.`,`Ułóż małą rozmowę o wietrznym dniu.`]},{day: 20, title: `Problemy i pomoc`, title_native: `Problemen en hulp`, focus: `Dziś uczysz się mówić, że masz problem i potrzebujesz pomocy. To przydatne na dworcu, w hotelu, przy zgubionym bagażu lub gdy nie możesz znaleźć drogi.`, vocab: [{nl: `probleem`, pl: `problem`, ipa: `/pro-blejm/`},{nl: `hulp`, pl: `pomoc`, ipa: `/hülp/`},{nl: `kwijt`, pl: `zgubiony`, ipa: `/kwejt/`},{nl: `tas`, pl: `torba`, ipa: `/tas/`},{nl: `telefoon`, pl: `telefon`, ipa: `/te-le-fon/`},{nl: `portemonnee`, pl: `portfel`, ipa: `/por-te-mo-nej/`},{nl: `politie`, pl: `policja`, ipa: `/po-li-si/`},{nl: `dokter`, pl: `lekarz`, ipa: `/dok-ter/`},{nl: `nood`, pl: `nagła potrzeba`, ipa: `/not/`},{nl: `veilig`, pl: `bezpieczny`, ipa: `/fej-lich/`}], phrases: [{nl: `Ik heb een probleem.`, pl: `Mam problem.`, ipa: `/ik heb en pro-blejm/`},{nl: `Kunt u mij helpen?`, pl: `Czy może mi pan/pani pomóc?`, ipa: `/künt ü mej hel-pen/`},{nl: `Ik ben mijn tas kwijt.`, pl: `Zgubiłem/Zgubiłam torbę.`, ipa: `/ik ben mejn tas kwejt/`},{nl: `Waar is de politie?`, pl: `Gdzie jest policja?`, ipa: `/war is de po-li-si/`},{nl: `Ik heb hulp nodig.`, pl: `Potrzebuję pomocy.`, ipa: `/ik heb hülp no-dich/`},{nl: `Is het hier veilig?`, pl: `Czy tutaj jest bezpiecznie?`, ipa: `/is het hir fej-lich/`}], grammar: `„Kunt u mij helpen?” to bardzo uprzejme i ważne pytanie. Konstrukcja „ik ben ... kwijt” oznacza, że coś zgubiłeś lub zgubiłaś. W sytuacjach stresowych najlepiej mówić krótkimi zdaniami: „Ik heb hulp nodig”.`, practice: [`Powiedz, że masz problem.`,`Poproś formalnie o pomoc.`,`Powiedz, że zgubiłeś torbę.`,`Zapytaj, gdzie jest policja.`,`Powiedz, że potrzebujesz pomocy.`]},{day: 21, title: `Apteka i zdrowie`, title_native: `Apotheek en gezondheid`, focus: `Dziś uczysz się podstawowych zwrotów w aptece. Przyda się to, gdy potrzebujesz leku przeciwbólowego, plastrów lub chcesz opisać proste objawy.`, vocab: [{nl: `apotheek`, pl: `apteka`, ipa: `/a-po-tejk/`},{nl: `medicijn`, pl: `lekarstwo`, ipa: `/me-di-sejn/`},{nl: `pijn`, pl: `ból`, ipa: `/pejn/`},{nl: `hoofdpijn`, pl: `ból głowy`, ipa: `/hoft-pejn/`},{nl: `buikpijn`, pl: `ból brzucha`, ipa: `/böjk-pejn/`},{nl: `pleister`, pl: `plaster`, ipa: `/plej-ster/`},{nl: `koorts`, pl: `gorączka`, ipa: `/korts/`},{nl: `verkoudheid`, pl: `przeziębienie`, ipa: `/fer-kaut-hejt/`},{nl: `water`, pl: `woda`, ipa: `/wa-ter/`},{nl: `rust`, pl: `odpoczynek`, ipa: `/rüst/`}], phrases: [{nl: `Waar is de apotheek?`, pl: `Gdzie jest apteka?`, ipa: `/war is de a-po-tejk/`},{nl: `Ik heb hoofdpijn.`, pl: `Boli mnie głowa.`, ipa: `/ik heb hoft-pejn/`},{nl: `Heeft u iets tegen pijn?`, pl: `Czy ma pan/pani coś przeciw bólowi?`, ipa: `/heft ü its te-chen pejn/`},{nl: `Ik heb pleisters nodig.`, pl: `Potrzebuję plastrów.`, ipa: `/ik heb plej-sters no-dich/`},{nl: `Ik ben verkouden.`, pl: `Jestem przeziębiony/przeziębiona.`, ipa: `/ik ben fer-kau-den/`},{nl: `Moet ik naar de dokter?`, pl: `Czy muszę iść do lekarza?`, ipa: `/mut ik nar de dok-ter/`}], grammar: `Objawy często opisuje się przez „Ik heb...”, np. „Ik heb hoofdpijn” — „Mam ból głowy”. „Iets tegen pijn” oznacza „coś przeciw bólowi”. W aptece warto używać formy formalnej „u”.`, practice: [`Zapytaj, gdzie jest apteka.`,`Powiedz, że boli cię głowa.`,`Poproś o coś przeciw bólowi.`,`Powiedz, że potrzebujesz plastrów.`,`Zapytaj, czy musisz iść do lekarza.`]},{day: 22, title: `Telefon i internet`, title_native: `Telefoon en internet`, focus: `Dziś ćwiczysz pytania o Wi-Fi, ładowarkę i telefon. To przydatne w hotelu, kawiarni, pociągu i przy pracy zdalnej w podróży.`, vocab: [{nl: `wifi`, pl: `Wi-Fi`, ipa: `/waj-faj/`},{nl: `wachtwoord`, pl: `hasło`, ipa: `/wacht-wort/`},{nl: `telefoon`, pl: `telefon`, ipa: `/te-le-fon/`},{nl: `oplader`, pl: `ładowarka`, ipa: `/op-la-der/`},{nl: `batterij`, pl: `bateria`, ipa: `/ba-te-rej/`},{nl: `internet`, pl: `internet`, ipa: `/in-ter-net/`},{nl: `stopcontact`, pl: `gniazdko`, ipa: `/stop-kon-takt/`},{nl: `bericht`, pl: `wiadomość`, ipa: `/be-richt/`},{nl: `bellen`, pl: `dzwonić`, ipa: `/be-len/`},{nl: `nummer`, pl: `numer`, ipa: `/nü-mer/`}], phrases: [{nl: `Wat is het wifi-wachtwoord?`, pl: `Jakie jest hasło do Wi-Fi?`, ipa: `/wat is het waj-faj wacht-wort/`},{nl: `Ik heb internet nodig.`, pl: `Potrzebuję internetu.`, ipa: `/ik heb in-ter-net no-dich/`},{nl: `Waar is een stopcontact?`, pl: `Gdzie jest gniazdko?`, ipa: `/war is en stop-kon-takt/`},{nl: `Mijn batterij is leeg.`, pl: `Moja bateria jest rozładowana.`, ipa: `/mejn ba-te-rej is lech/`},{nl: `Mag ik hier bellen?`, pl: `Czy mogę tu zadzwonić?`, ipa: `/mach ik hir be-len/`},{nl: `Wat is uw nummer?`, pl: `Jaki jest pana/pani numer?`, ipa: `/wat is üw nü-mer/`}], grammar: `„Wat is...?” działa w wielu prostych pytaniach o informacje. „Uw” to formalne „pana/pani”, a „jouw” to nieformalne „twoje”. Przy pytaniu o numer do hotelu lub firmy używaj „uw nummer”.`, practice: [`Zapytaj o hasło do Wi-Fi.`,`Powiedz, że potrzebujesz internetu.`,`Zapytaj o gniazdko.`,`Powiedz, że bateria jest rozładowana.`,`Zapytaj formalnie o numer telefonu.`]},{day: 23, title: `Spotkania towarzyskie`, title_native: `Sociale ontmoetingen`, focus: `Dziś uczysz się prostych zdań do rozmowy z lokalnymi osobami. Przyda się to w barze, hostelu, na wydarzeniu lub podczas wspólnej wycieczki.`, vocab: [{nl: `vriend`, pl: `przyjaciel`, ipa: `/frint/`},{nl: `vriendin`, pl: `przyjaciółka, dziewczyna`, ipa: `/frin-din/`},{nl: `gezellig`, pl: `przyjemny, miły towarzysko`, ipa: `/che-zel-lich/`},{nl: `feest`, pl: `impreza`, ipa: `/fejst/`},{nl: `muziek`, pl: `muzyka`, ipa: `/mü-zik/`},{nl: `bier`, pl: `piwo`, ipa: `/bir/`},{nl: `wijn`, pl: `wino`, ipa: `/wejn/`},{nl: `praten`, pl: `rozmawiać`, ipa: `/pra-ten/`},{nl: `luisteren`, pl: `słuchać`, ipa: `/löj-ste-ren/`},{nl: `leuk`, pl: `fajny`, ipa: `/lök/`}], phrases: [{nl: `Het is gezellig hier.`, pl: `Tu jest przyjemnie.`, ipa: `/het is che-zel-lich hir/`},{nl: `Waar kom je vandaan?`, pl: `Skąd pochodzisz?`, ipa: `/war kom je fan-dan/`},{nl: `Ik kom uit Polen.`, pl: `Pochodzę z Polski.`, ipa: `/ik kom aut po-len/`},{nl: `Hou je van muziek?`, pl: `Lubisz muzykę?`, ipa: `/hau je fan mü-zik/`},{nl: `Dat is leuk.`, pl: `To fajne.`, ipa: `/dat is lök/`},{nl: `Zullen we praten?`, pl: `Porozmawiamy?`, ipa: `/zü-len we pra-ten/`}], grammar: `„Gezellig” to ważne niderlandzkie słowo bez idealnego polskiego odpowiednika. Oznacza coś miłego, przytulnego, towarzyskiego i przyjemnego. „Hou je van...?” znaczy „Czy lubisz...?” i działa przy muzyce, jedzeniu, miejscach i aktywnościach.`, practice: [`Powiedz, że tu jest przyjemnie.`,`Zapytaj kogoś, skąd pochodzi.`,`Powiedz, że pochodzisz z Polski.`,`Zapytaj, czy ktoś lubi muzykę.`,`Ułóż krótką rozmowę w hostelu.`]},{day: 24, title: `Zaproszenia i plany`, title_native: `Uitnodigingen en plannen`, focus: `Dziś uczysz się proponować spotkanie, akceptować i odmawiać. To przyda się, gdy poznasz kogoś w Utrechcie i chcesz pójść razem na kawę albo spacer.`, vocab: [{nl: `vandaag`, pl: `dzisiaj`, ipa: `/fan-dach/`},{nl: `morgen`, pl: `jutro`, ipa: `/mor-chen/`},{nl: `vanavond`, pl: `dziś wieczorem`, ipa: `/fan-a-font/`},{nl: `samen`, pl: `razem`, ipa: `/sa-men/`},{nl: `koffie`, pl: `kawa`, ipa: `/ko-fi/`},{nl: `wandelen`, pl: `spacerować`, ipa: `/wan-de-len/`},{nl: `tijd`, pl: `czas`, ipa: `/teit/`},{nl: `zin`, pl: `ochota`, ipa: `/zin/`},{nl: `misschien`, pl: `może`, ipa: `/mis-schin/`},{nl: `afspreken`, pl: `umówić się`, ipa: `/af-sprej-ken/`}], phrases: [{nl: `Heb je vanavond tijd?`, pl: `Masz dziś wieczorem czas?`, ipa: `/heb je fan-a-font teit/`},{nl: `Zullen we koffie drinken?`, pl: `Napijemy się kawy?`, ipa: `/zü-len we ko-fi drin-ken/`},{nl: `Ik heb zin in koffie.`, pl: `Mam ochotę na kawę.`, ipa: `/ik heb zin in ko-fi/`},{nl: `Misschien morgen.`, pl: `Może jutro.`, ipa: `/mis-schin mor-chen/`},{nl: `Dat klinkt goed.`, pl: `To brzmi dobrze.`, ipa: `/dat klinkt chut/`},{nl: `Sorry, ik kan niet.`, pl: `Przepraszam, nie mogę.`, ipa: `/so-ri ik kan nit/`}], grammar: `„Zullen we...?” to naturalny sposób proponowania wspólnego działania. „Ik heb zin in...” oznacza „mam ochotę na...”. Odmowa „Sorry, ik kan niet” jest prosta, grzeczna i wystarczająco jasna.`, practice: [`Zapytaj, czy ktoś ma wieczorem czas.`,`Zaproponuj kawę.`,`Powiedz, że masz ochotę na kawę.`,`Odmów grzecznie.`,`Zaproponuj spotkanie jutro.`]},{day: 25, title: `Wypożyczanie roweru`, title_native: `Een fiets huren`, focus: `Dziś uczysz się zwrotów związanych z rowerem, bardzo ważnym środkiem transportu w Niderlandach. Scena pasuje do wypożyczalni rowerów w Amsterdamie, Utrechcie lub Groningen.`, vocab: [{nl: `fiets`, pl: `rower`, ipa: `/fits/`},{nl: `huren`, pl: `wypożyczyć`, ipa: `/hü-ren/`},{nl: `slot`, pl: `zamek`, ipa: `/slot/`},{nl: `helm`, pl: `kask`, ipa: `/helm/`},{nl: `pad`, pl: `ścieżka`, ipa: `/pat/`},{nl: `fietspad`, pl: `ścieżka rowerowa`, ipa: `/fits-pat/`},{nl: `rem`, pl: `hamulec`, ipa: `/rem/`},{nl: `licht`, pl: `światło`, ipa: `/licht/`},{nl: `dag`, pl: `dzień`, ipa: `/dach/`},{nl: `uur`, pl: `godzina`, ipa: `/ür/`}], phrases: [{nl: `Ik wil een fiets huren.`, pl: `Chcę wypożyczyć rower.`, ipa: `/ik wil en fits hü-ren/`},{nl: `Voor één dag, alstublieft.`, pl: `Na jeden dzień, proszę.`, ipa: `/for ejn dach als-tü-blift/`},{nl: `Heeft u een slot?`, pl: `Czy ma pan/pani zamek?`, ipa: `/heft ü en slot/`},{nl: `Waar is het fietspad?`, pl: `Gdzie jest ścieżka rowerowa?`, ipa: `/war is het fits-pat/`},{nl: `De rem werkt niet.`, pl: `Hamulec nie działa.`, ipa: `/de rem werkt nit/`},{nl: `Is een helm nodig?`, pl: `Czy kask jest potrzebny?`, ipa: `/is en helm no-dich/`}], grammar: `Czasownik „huren” oznacza wypożyczać lub wynajmować. W Niderlandach rowerzyści mają własne zasady i ścieżki, więc słowo „fietspad” jest bardzo ważne. „Werkt niet” znaczy „nie działa” i przyda się także przy telefonie, karcie lub automacie.`, practice: [`Powiedz, że chcesz wypożyczyć rower.`,`Poproś o rower na jeden dzień.`,`Zapytaj o zamek.`,`Powiedz, że hamulec nie działa.`,`Zapytaj, gdzie jest ścieżka rowerowa.`]},{day: 26, title: `Pociągi między miastami`, title_native: `Treinen tussen steden`, focus: `Dziś rozwijasz temat podróży koleją między miastami. Nauczysz się pytać o przesiadki, perony, opóźnienia i bilety do Utrechtu, Hagi lub Rotterdamu.`, vocab: [{nl: `intercity`, pl: `pociąg intercity`, ipa: `/in-ter-si-ti/`},{nl: `sprinter`, pl: `pociąg lokalny`, ipa: `/sprin-ter/`},{nl: `retour`, pl: `bilet powrotny`, ipa: `/re-tur/`},{nl: `enkele reis`, pl: `bilet w jedną stronę`, ipa: `/en-ke-le rejs/`},{nl: `aankomen`, pl: `przyjechać`, ipa: `/an-ko-men/`},{nl: `vertrekken`, pl: `odjechać`, ipa: `/fer-tre-ken/`},{nl: `spoor`, pl: `tor, peron`, ipa: `/spor/`},{nl: `conducteur`, pl: `konduktor`, ipa: `/kon-dük-tör/`},{nl: `kaartcontrole`, pl: `kontrola biletów`, ipa: `/kart-kon-tro-le/`},{nl: `reis`, pl: `podróż`, ipa: `/rejs/`}], phrases: [{nl: `Een retour naar Utrecht, graag.`, pl: `Bilet powrotny do Utrechtu, poproszę.`, ipa: `/en re-tur nar ü-trecht chrach/`},{nl: `Is dit de trein naar Den Haag?`, pl: `Czy to pociąg do Hagi?`, ipa: `/is dit de trejn nar den hach/`},{nl: `Hoe laat komt de trein aan?`, pl: `O której pociąg przyjeżdża?`, ipa: `/hu lat komt de trejn an/`},{nl: `Moet ik hier overstappen?`, pl: `Czy muszę się tutaj przesiąść?`, ipa: `/mut ik hir o-fer-sta-pen/`},{nl: `Waar is spoor vijf?`, pl: `Gdzie jest peron piąty?`, ipa: `/war is spor fejf/`},{nl: `Ik heb al een ticket.`, pl: `Już mam bilet.`, ipa: `/ik heb al en ti-ket/`}], grammar: `„Naar” pokazuje kierunek podróży, a „aan komen” oznacza „przyjeżdżać”. „Al” oznacza „już”, więc „Ik heb al een ticket” brzmi naturalnie przy kontroli. Pamiętaj, że nazwy miast często mają rodzajnik lub stałą formę, np. „Den Haag”.`, practice: [`Kup bilet powrotny do Utrechtu.`,`Zapytaj, czy to pociąg do Hagi.`,`Zapytaj, o której pociąg przyjeżdża.`,`Powiedz, że już masz bilet.`,`Zapytaj o peron piąty.`]},{day: 27, title: `Mieszkanie i codzienne sprawy`, title_native: `Wonen en dagelijkse zaken`, focus: `Dziś uczysz się mówić o prostych sprawach codziennego życia, takich jak pranie, pokój, klucz i sąsiedztwo. Przyda się to w apartamencie krótkoterminowym lub hostelu.`, vocab: [{nl: `woning`, pl: `mieszkanie`, ipa: `/wo-ning/`},{nl: `kamer`, pl: `pokój`, ipa: `/ka-mer/`},{nl: `keuken`, pl: `kuchnia`, ipa: `/kö-ken/`},{nl: `badkamer`, pl: `łazienka`, ipa: `/bat-ka-mer/`},{nl: `wasmachine`, pl: `pralka`, ipa: `/was-ma-szi-ne/`},{nl: `sleutel`, pl: `klucz`, ipa: `/slöj-tel/`},{nl: `deur`, pl: `drzwi`, ipa: `/dör/`},{nl: `raam`, pl: `okno`, ipa: `/ram/`},{nl: `buurt`, pl: `okolica`, ipa: `/bürt/`},{nl: `stil`, pl: `cicho`, ipa: `/stil/`}], phrases: [{nl: `Waar is de wasmachine?`, pl: `Gdzie jest pralka?`, ipa: `/war is de was-ma-szi-ne/`},{nl: `De sleutel werkt niet.`, pl: `Klucz nie działa.`, ipa: `/de slöj-tel werkt nit/`},{nl: `De kamer is schoon.`, pl: `Pokój jest czysty.`, ipa: `/de ka-mer is schon/`},{nl: `Is de buurt veilig?`, pl: `Czy okolica jest bezpieczna?`, ipa: `/is de bürt fej-lich/`},{nl: `Het raam is open.`, pl: `Okno jest otwarte.`, ipa: `/het ram is o-pen/`},{nl: `Het is hier stil.`, pl: `Tutaj jest cicho.`, ipa: `/het is hir stil/`}], grammar: `Przymiotniki takie jak „schoon”, „veilig” i „stil” są bardzo użyteczne przy opisywaniu miejsc. „Werkt niet” można stosować do wielu rzeczy: klucza, Wi-Fi, pralki, karty. W wynajmie krótkoterminowym jasne zdania pomagają szybko rozwiązać problem.`, practice: [`Zapytaj, gdzie jest pralka.`,`Powiedz, że klucz nie działa.`,`Opisz pokój jako czysty.`,`Zapytaj, czy okolica jest bezpieczna.`,`Powiedz, że okno jest otwarte.`]},{day: 28, title: `Opinie i porównania`, title_native: `Meningen en vergelijkingen`, focus: `Dziś uczysz się mówić, co lubisz, czego nie lubisz i co jest lepsze. To przydatne przy wyborze restauracji, kawiarni, muzeum lub trasy zwiedzania.`, vocab: [{nl: `mooi`, pl: `ładny, piękny`, ipa: `/moj/`},{nl: `lelijk`, pl: `brzydki`, ipa: `/lej-lik/`},{nl: `goed`, pl: `dobry`, ipa: `/chut/`},{nl: `beter`, pl: `lepszy`, ipa: `/be-ter/`},{nl: `slecht`, pl: `zły`, ipa: `/slecht/`},{nl: `duur`, pl: `drogi`, ipa: `/dür/`},{nl: `goedkoop`, pl: `tani`, ipa: `/chut-kop/`},{nl: `druk`, pl: `zatłoczony`, ipa: `/drük/`},{nl: `rustig`, pl: `spokojny`, ipa: `/rüs-tach/`},{nl: `favoriet`, pl: `ulubiony`, ipa: `/fa-fo-rit/`}], phrases: [{nl: `Ik vind dit mooi.`, pl: `Uważam, że to jest ładne.`, ipa: `/ik fint dit moj/`},{nl: `Dit restaurant is beter.`, pl: `Ta restauracja jest lepsza.`, ipa: `/dit res-to-rant is be-ter/`},{nl: `Het is te druk.`, pl: `Jest zbyt tłoczno.`, ipa: `/het is te drük/`},{nl: `Ik hou van rustige cafés.`, pl: `Lubię spokojne kawiarnie.`, ipa: `/ik hau fan rüs-ta-che ka-fejs/`},{nl: `Wat vind je ervan?`, pl: `Co o tym sądzisz?`, ipa: `/wat fint je er-fan/`},{nl: `Dit is mijn favoriet.`, pl: `To jest mój ulubiony.`, ipa: `/dit is mejn fa-fo-rit/`}], grammar: `„Ik vind...” służy do wyrażania opinii i często znaczy „uważam, że...”. „Ik hou van...” oznacza „lubię” albo „kocham”, zależnie od kontekstu. „Te” przed przymiotnikiem oznacza „zbyt”, np. „te druk” — „zbyt tłoczno”.`, practice: [`Powiedz, że coś jest ładne.`,`Powiedz, że restauracja jest lepsza.`,`Powiedz, że jest zbyt tłoczno.`,`Zapytaj kogoś o opinię.`,`Powiedz, że coś jest twoim ulubionym miejscem.`]},{day: 29, title: `Sytuacje awaryjne`, title_native: `Noodsituaties`, focus: `Dziś uczysz się ważnych zdań na sytuacje awaryjne. Nie musisz mówić perfekcyjnie — celem jest szybko przekazać, czego potrzebujesz.`, vocab: [{nl: `noodgeval`, pl: `nagły wypadek`, ipa: `/not-che-fal/`},{nl: `ambulance`, pl: `ambulans`, ipa: `/am-bü-lans/`},{nl: `brand`, pl: `pożar`, ipa: `/brant/`},{nl: `politie`, pl: `policja`, ipa: `/po-li-si/`},{nl: `ziek`, pl: `chory`, ipa: `/zik/`},{nl: `gewond`, pl: `ranny`, ipa: `/che-wont/`},{nl: `help`, pl: `pomocy`, ipa: `/help/`},{nl: `snel`, pl: `szybko`, ipa: `/snel/`},{nl: `adres`, pl: `adres`, ipa: `/a-dres/`},{nl: `gevaar`, pl: `niebezpieczeństwo`, ipa: `/che-far/`}], phrases: [{nl: `Help!`, pl: `Pomocy!`, ipa: `/help/`},{nl: `Bel de politie!`, pl: `Proszę zadzwonić na policję!`, ipa: `/bel de po-li-si/`},{nl: `Ik heb een ambulance nodig.`, pl: `Potrzebuję ambulansu.`, ipa: `/ik heb en am-bü-lans no-dich/`},{nl: `Er is brand.`, pl: `Jest pożar.`, ipa: `/er is brant/`},{nl: `Ik ben ziek.`, pl: `Jestem chory/chora.`, ipa: `/ik ben zik/`},{nl: `Dit is mijn adres.`, pl: `To jest mój adres.`, ipa: `/dit is mejn a-dres/`}], grammar: `W sytuacji awaryjnej krótkie zdania są najlepsze. Tryb rozkazujący może być bardzo prosty: „Bel...” oznacza „zadzwoń”. „Nodig hebben” znowu pojawia się w formie „Ik heb ... nodig”, czyli „potrzebuję...”.`, practice: [`Zawołaj „Pomocy!” po niderlandzku.`,`Powiedz, że potrzebujesz ambulansu.`,`Powiedz, że jest pożar.`,`Powiedz, że jesteś chory/chora.`,`Podaj swój adres prostym zdaniem.`]},{day: 30, title: `Pełny dzień podróży`, title_native: `Een volledige reisdag`, focus: `Dziś łączysz wszystko: hotel, transport, jedzenie, zakupy, pytania i uprzejmości. Wyobraź sobie pełny dzień w Amsterdamie z przejazdem do Utrechtu i kolacją wieczorem.`, vocab: [{nl: `reisdag`, pl: `dzień podróży`, ipa: `/rejs-dach/`},{nl: `plan`, pl: `plan`, ipa: `/plan/`},{nl: `ochtend`, pl: `poranek`, ipa: `/och-tent/`},{nl: `middag`, pl: `popołudnie`, ipa: `/mi-dach/`},{nl: `avond`, pl: `wieczór`, ipa: `/a-font/`},{nl: `station`, pl: `stacja, dworzec`, ipa: `/sta-sjon/`},{nl: `restaurant`, pl: `restauracja`, ipa: `/res-to-rant/`},{nl: `museum`, pl: `muzeum`, ipa: `/mü-ze-üm/`},{nl: `kaartje`, pl: `bilet`, ipa: `/kar-cze/`},{nl: `rekening`, pl: `rachunek`, ipa: `/rej-ke-ning/`}], phrases: [{nl: `Vandaag ga ik naar Utrecht.`, pl: `Dzisiaj jadę do Utrechtu.`, ipa: `/fan-dach cha ik nar ü-trecht/`},{nl: `Eerst ga ik naar het station.`, pl: `Najpierw idę na dworzec.`, ipa: `/erst cha ik nar het sta-sjon/`},{nl: `Daarna bezoek ik een museum.`, pl: `Potem odwiedzam muzeum.`, ipa: `/dar-na be-zuk ik en mü-ze-üm/`},{nl: `Ik eet in een restaurant.`, pl: `Jem w restauracji.`, ipa: `/ik ejt in en res-to-rant/`},{nl: `Mag ik de rekening?`, pl: `Czy mogę dostać rachunek?`, ipa: `/mach ik de rej-ke-ning/`},{nl: `Tot morgen en bedankt.`, pl: `Do jutra i dziękuję.`, ipa: `/tot mor-chen en be-dankt/`}], grammar: `Do opowiadania planu dnia przydają się słowa „eerst” — „najpierw” i „daarna” — „potem”. Czas teraźniejszy w niderlandzkim często wystarcza do mówienia o bliskiej przyszłości, np. „Vandaag ga ik...”. To bardzo praktyczne dla podróżnika.`, practice: [`Powiedz, że dziś jedziesz do Utrechtu.`,`Ułóż plan dnia z „eerst” i „daarna”.`,`Zamów posiłek w restauracji.`,`Zapytaj o bilet i peron.`,`Napisz mini-dialog obejmujący hotel, dworzec i kawiarnię.`]}];

var CONVERSATIONS_PL_NL = [{id: 1, title: `Zamawianie w kawiarni`, scene: `Jesteś w małej kawiarni w Amsterdamie, blisko kanału. Chcesz zamówić kawę, coś słodkiego i zapytać, czy możesz zapłacić kartą.`, lines: [{who: `them`, nl: `Goedemorgen, wat wilt u drinken?`, pl: `Dzień dobry, co chce pan/pani do picia?`},{who: `you`, nl: `Goedemorgen, een koffie met melk, graag.`, pl: `Dzień dobry, kawę z mlekiem, poproszę.`},{who: `them`, nl: `Wilt u suiker?`, pl: `Czy chce pan/pani cukier?`},{who: `you`, nl: `Nee, zonder suiker, alstublieft.`, pl: `Nie, bez cukru, proszę.`},{who: `them`, nl: `Wilt u er iets bij?`, pl: `Czy chce pan/pani coś do tego?`},{who: `you`, nl: `Ja, een stuk taart, graag.`, pl: `Tak, kawałek ciasta, poproszę.`},{who: `them`, nl: `Voor hier of om mee te nemen?`, pl: `Na miejscu czy na wynos?`},{who: `you`, nl: `Voor hier, graag.`, pl: `Na miejscu, poproszę.`},{who: `them`, nl: `Dat is acht euro vijftig.`, pl: `To będzie osiem euro pięćdziesiąt.`},{who: `you`, nl: `Kan ik met kaart betalen?`, pl: `Czy mogę zapłacić kartą?`},{who: `them`, nl: `Ja, natuurlijk.`, pl: `Tak, oczywiście.`},{who: `you`, nl: `Dank u wel.`, pl: `Bardzo dziękuję.`}]},{id: 2, title: `Zameldowanie w hotelu`, scene: `Przyjeżdżasz do hotelu w Hadze po południu. Masz rezerwację i chcesz zapytać o śniadanie oraz windę.`, lines: [{who: `them`, nl: `Goedenmiddag, welkom in ons hotel.`, pl: `Dzień dobry, witamy w naszym hotelu.`},{who: `you`, nl: `Goedemiddag, ik heb een reservering.`, pl: `Dzień dobry, mam rezerwację.`},{who: `them`, nl: `Op welke naam?`, pl: `Na jakie nazwisko?`},{who: `you`, nl: `Op naam van Kowalski.`, pl: `Na nazwisko Kowalski.`},{who: `them`, nl: `Ja, ik zie uw reservering.`, pl: `Tak, widzę pana/pani rezerwację.`},{who: `you`, nl: `Is ontbijt inbegrepen?`, pl: `Czy śniadanie jest wliczone?`},{who: `them`, nl: `Ja, ontbijt is van zeven tot tien uur.`, pl: `Tak, śniadanie jest od siódmej do dziesiątej.`},{who: `you`, nl: `Dank u, waar is de lift?`, pl: `Dziękuję, gdzie jest winda?`},{who: `them`, nl: `De lift is rechts, naast de receptie.`, pl: `Winda jest po prawej, obok recepcji.`},{who: `you`, nl: `Mag ik de sleutel?`, pl: `Czy mogę dostać klucz?`},{who: `them`, nl: `Natuurlijk, kamer driehonderd twee.`, pl: `Oczywiście, pokój trzysta dwa.`},{who: `you`, nl: `Bedankt en tot ziens.`, pl: `Dziękuję i do widzenia.`}]},{id: 3, title: `Pytanie o drogę`, scene: `Jesteś w Utrechcie i szukasz dworca. Zatrzymujesz lokalną osobę na ulicy i pytasz o prostą trasę.`, lines: [{who: `you`, nl: `Sorry, kunt u mij helpen?`, pl: `Przepraszam, czy może mi pan/pani pomóc?`},{who: `them`, nl: `Ja, natuurlijk.`, pl: `Tak, oczywiście.`},{who: `you`, nl: `Waar is het station?`, pl: `Gdzie jest dworzec?`},{who: `them`, nl: `Ga rechtdoor en sla dan linksaf.`, pl: `Idź prosto, a potem skręć w lewo.`},{who: `you`, nl: `Is het ver?`, pl: `Czy to daleko?`},{who: `them`, nl: `Nee, het is ongeveer tien minuten lopen.`, pl: `Nie, to około dziesięć minut pieszo.`},{who: `you`, nl: `Moet ik over de brug?`, pl: `Czy muszę przejść przez most?`},{who: `them`, nl: `Ja, bij de brug gaat u rechts.`, pl: `Tak, przy moście idzie pan/pani w prawo.`},{who: `you`, nl: `Dank u wel.`, pl: `Bardzo dziękuję.`},{who: `them`, nl: `Geen probleem.`, pl: `Nie ma problemu.`},{who: `you`, nl: `Fijne dag.`, pl: `Miłego dnia.`},{who: `them`, nl: `U ook.`, pl: `Panu/Pani też.`}]},{id: 4, title: `Kolacja w restauracji`, scene: `Wieczorem jesteś w restauracji w Rotterdamie. Chcesz stolik dla dwóch osób, pytasz o polecenie i prosisz o rachunek.`, lines: [{who: `them`, nl: `Goedenavond, heeft u gereserveerd?`, pl: `Dobry wieczór, czy ma pan/pani rezerwację?`},{who: `you`, nl: `Nee, heeft u een tafel voor twee?`, pl: `Nie, czy mają państwo stolik dla dwóch osób?`},{who: `them`, nl: `Ja, natuurlijk, hier alstublieft.`, pl: `Tak, oczywiście, tutaj proszę.`},{who: `you`, nl: `Mag ik het menu?`, pl: `Czy mogę dostać menu?`},{who: `them`, nl: `Ja, hier is het menu.`, pl: `Tak, oto menu.`},{who: `you`, nl: `Wat raadt u aan?`, pl: `Co pan/pani poleca?`},{who: `them`, nl: `De vis is vandaag erg lekker.`, pl: `Ryba jest dziś bardzo smaczna.`},{who: `you`, nl: `Dan neem ik de vis, graag.`, pl: `W takim razie wezmę rybę, poproszę.`},{who: `them`, nl: `Wilt u iets drinken?`, pl: `Czy chce pan/pani coś do picia?`},{who: `you`, nl: `Een glas water en een wijn, graag.`, pl: `Szklankę wody i wino, poproszę.`},{who: `them`, nl: `Natuurlijk.`, pl: `Oczywiście.`},{who: `you`, nl: `Mag ik straks de rekening?`, pl: `Czy mogę później dostać rachunek?`}]},{id: 5, title: `Kupowanie biletu na pociąg`, scene: `Jesteś na dworcu Amsterdam Centraal i chcesz kupić bilet powrotny do Utrechtu. Pytasz też o peron i przesiadkę.`, lines: [{who: `them`, nl: `Goedemorgen, waar wilt u naartoe?`, pl: `Dzień dobry, dokąd chce pan/pani jechać?`},{who: `you`, nl: `Een retour naar Utrecht, graag.`, pl: `Bilet powrotny do Utrechtu, poproszę.`},{who: `them`, nl: `Voor vandaag?`, pl: `Na dzisiaj?`},{who: `you`, nl: `Ja, voor vandaag.`, pl: `Tak, na dzisiaj.`},{who: `them`, nl: `Dat is twintig euro.`, pl: `To będzie dwadzieścia euro.`},{who: `you`, nl: `Kan ik met kaart betalen?`, pl: `Czy mogę zapłacić kartą?`},{who: `them`, nl: `Ja, dat kan.`, pl: `Tak, można.`},{who: `you`, nl: `Welk spoor is het?`, pl: `Który peron?`},{who: `them`, nl: `Spoor vijf.`, pl: `Peron piąty.`},{who: `you`, nl: `Moet ik overstappen?`, pl: `Czy muszę się przesiąść?`},{who: `them`, nl: `Nee, het is een directe trein.`, pl: `Nie, to bezpośredni pociąg.`},{who: `you`, nl: `Bedankt.`, pl: `Dziękuję.`}]},{id: 6, title: `Zakupy w sklepie`, scene: `Jesteś w sklepie odzieżowym w Amsterdamie. Szukasz butów, pytasz o rozmiar i chcesz coś przymierzyć.`, lines: [{who: `them`, nl: `Hallo, kan ik u helpen?`, pl: `Dzień dobry, czy mogę pomóc?`},{who: `you`, nl: `Ja, ik zoek schoenen.`, pl: `Tak, szukam butów.`},{who: `them`, nl: `Welke maat heeft u?`, pl: `Jaki ma pan/pani rozmiar?`},{who: `you`, nl: `Maat tweeënveertig.`, pl: `Rozmiar czterdzieści dwa.`},{who: `them`, nl: `Deze schoenen zijn er in zwart en wit.`, pl: `Te buty są dostępne w czarnym i białym kolorze.`},{who: `you`, nl: `Heeft u deze in zwart?`, pl: `Czy mają państwo te w czarnym kolorze?`},{who: `them`, nl: `Ja, natuurlijk.`, pl: `Tak, oczywiście.`},{who: `you`, nl: `Kan ik ze passen?`, pl: `Czy mogę je przymierzyć?`},{who: `them`, nl: `De paskamer is daar links.`, pl: `Przymierzalnia jest tam po lewej.`},{who: `you`, nl: `Ze zijn een beetje te klein.`, pl: `Są trochę za małe.`},{who: `them`, nl: `Ik breng een grotere maat.`, pl: `Przyniosę większy rozmiar.`},{who: `you`, nl: `Dank je.`, pl: `Dzięki.`}]},{id: 7, title: `W aptece`, scene: `Źle się czujesz podczas podróży w Delft. Wchodzisz do apteki, żeby poprosić o coś na ból głowy i kupić plastry.`, lines: [{who: `them`, nl: `Goedemiddag, kan ik u helpen?`, pl: `Dzień dobry, czy mogę pomóc?`},{who: `you`, nl: `Ja, ik heb hoofdpijn.`, pl: `Tak, boli mnie głowa.`},{who: `them`, nl: `Heeft u ook koorts?`, pl: `Czy ma pan/pani też gorączkę?`},{who: `you`, nl: `Nee, geen koorts.`, pl: `Nie, bez gorączki.`},{who: `them`, nl: `Wilt u iets tegen pijn?`, pl: `Czy chce pan/pani coś przeciw bólowi?`},{who: `you`, nl: `Ja, alstublieft.`, pl: `Tak, proszę.`},{who: `them`, nl: `Neem dit met water.`, pl: `Proszę wziąć to z wodą.`},{who: `you`, nl: `Dank u, ik heb ook pleisters nodig.`, pl: `Dziękuję, potrzebuję też plastrów.`},{who: `them`, nl: `Natuurlijk, kleine of grote pleisters?`, pl: `Oczywiście, małe czy duże plastry?`},{who: `you`, nl: `Kleine pleisters, graag.`, pl: `Małe plastry, poproszę.`},{who: `them`, nl: `Dat is zes euro.`, pl: `To będzie sześć euro.`},{who: `you`, nl: `Ik betaal met kaart.`, pl: `Płacę kartą.`}]},{id: 8, title: `Rozmowa z lokalną osobą`, scene: `Siedzisz w spokojnej kawiarni w Groningen i zaczynasz rozmowę z lokalną osobą przy wspólnym stole. Chcesz poćwiczyć mały small talk o mieście, pogodzie i planach.`, lines: [{who: `you`, nl: `Hallo, is deze stoel vrij?`, pl: `Cześć, czy to krzesło jest wolne?`},{who: `them`, nl: `Ja, natuurlijk.`, pl: `Tak, oczywiście.`},{who: `you`, nl: `Dank je, het is gezellig hier.`, pl: `Dzięki, tu jest przyjemnie.`},{who: `them`, nl: `Ja, dit café is heel leuk.`, pl: `Tak, ta kawiarnia jest bardzo fajna.`},{who: `you`, nl: `Kom je uit Groningen?`, pl: `Pochodzisz z Groningen?`},{who: `them`, nl: `Ja, ik woon hier.`, pl: `Tak, mieszkam tutaj.`},{who: `you`, nl: `Ik kom uit Polen en bezoek Nederland.`, pl: `Pochodzę z Polski i odwiedzam Niderlandy.`},{who: `them`, nl: `Wat vind je van de stad?`, pl: `Co sądzisz o mieście?`},{who: `you`, nl: `Ik vind de stad mooi en rustig.`, pl: `Uważam, że miasto jest piękne i spokojne.`},{who: `them`, nl: `Het weer is vandaag ook goed.`, pl: `Pogoda też jest dziś dobra.`},{who: `you`, nl: `Ja, geen regen vandaag.`, pl: `Tak, dziś bez deszczu.`},{who: `them`, nl: `Veel plezier in Nederland.`, pl: `Miłego pobytu w Niderlandach.`}]}];